var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"3일 뒤, 국경 밖.","JPN":"3日後、国境の外。","ENG":"3 days later. Outside the border.","TWN":"3天後 國境外","THA":"3 วันต่อมา นอกชายแดน","VTN":"3 ngày sau. Bên ngoài biên giới.","SCN":"3天后，边境外。","DEU":"3 Tage später. Außerhalb der Grenze.","FRA":"3 jours plus tard, à l'extérieur."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"폐쇄된 구 남부횡단열차 종착역. \\n노르드나빅 포기거점. 디어루트 외성 부근.","JPN":"閉鎖された旧南部横断列車の終着駅。\\nノルドナビックの放棄拠点。ディアルート外郭付近。","ENG":"[[","TWN":"封鎖的舊南方縱貫列車終點站 \\n諾爾德萊比放棄據點 迪魯特外城附近","THA":"สถานีปลายทางที่ถูกปิดกั้นของทางรถไฟสายใต้\\nฐานร้างของนอร์ดเนวิก ใกล้ปราสาทชั้นนอกเดียร์รูต","VTN":"Nhà ga đóng cửa của Vận chuyển Đường sắt phía Nam cũ.\\nCăn cứ Nordnavik bị bỏ hoang. Gần Lâu đài bên ngoài Rễ Hươu.","SCN":"封闭的原南部横贯列车终点站。\\n诺德纳维克弃置据点，迪尔鲁特外城附近。","DEU":"Gesperrte Endstation des altes Südlichen Transitzugs.\\nVerlassener Nordnavik-Stützpunkt. In der Nähe der Außenburg Hirschwurzel.","FRA":"Voie ferrée abandonnée, station d'arrivage.\\nÀ proximité du Fort de Haute-Ramure."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"어엇, 물자들 쓰러지지 않게 조심해!","JPN":"おおっと、物資が倒れないように気をつけろよ！","ENG":"Hey! Be careful not to drop the supplies!","TWN":"喂，小心別弄倒物資！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"바람도 엄청 불고, 피부가 얼어붙겠네.","JPN":"風もすごく強いし、肌が凍りそうだ。","ENG":"It's so windy out here, It feels like my skin's about to turn into ice!","TWN":"風好大，臉好冰喔！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"여긴 완전히 겨울이군. 우린 침식지대 한복판에 들어온 거야.","JPN":"ここはすっかり冬だな。俺らは侵食地帯のど真ん中に入ってきたんだ。","ENG":"It's a full-blown winter here. We just walked into the center of a Corrupted Area.","TWN":"這裡根本完全是冬天，看來我們進到侵蝕地帶的中心。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"디어루트에는 처음 와봐요. 이전에 사람이 살던 곳이라곤 믿기지 않네요.","JPN":"ディアルートは初めてですね。以前人が住んでたなんて信じられませんよ。","ENG":"It's my first time in Deer Root. I still can't believe people used to live here.","TWN":"我是第一次來迪魯特，真不敢相信這裡以前有住人。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"한때는 노르드나빅에서 가장 규모가 큰 광산도시였어. 나도 어렸을 땐 잠깐 이곳에서 갱도를 뚫는 기술자로 일했었지.","JPN":"一時はノルドナビックでもっとも大きな鉱山都市だったんだ。俺も若い頃ここで坑道を掘る技術者としてちょっと働いてたんだぞ。","ENG":"This was once Nordnavik's largest mining town. I briefly worked as a tunneling technician here when I was younger.","TWN":"這裡曾經是諾爾德萊比規模最大的礦產都市，我小時候也在這裡當過打通坑道的技術人員。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"그러고보니 와트 씨는 왜 군인이 되신 거예요? 재건단에선 기술자가 많이 필요하다고 들었는데.","JPN":"そういえば、ワットさんってなんで入隊したんですか？　再建団には技術者がもっと必要だって聞きましたけど。","ENG":"Come to think of it, why did you join the army, Mr. Watt? Didn't the Alliance need a lot of technicians or something?","TWN":"那你為什麼會成爲軍人？我聽說重建委員不是需要很多技師嗎？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"처음엔 나도 수도로 가려고 했었어.","JPN":"最初は俺も首都に行こうとしてたさ。","ENG":"I was thinking of heading to the capital once.","TWN":"一開始我也想去首都。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"그런데 피난 도중에 약혼자가 죽었거든. 침식체들한테.","JPN":"でも避難中にフィアンセが死んじまったんだ。侵食体によってな。","ENG":"But during the evacuation, my fiancée got killed by those C.O.s.","TWN":"可是在逃難的途中，未婚妻被侵蝕體害死。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"……몰랐어요.","JPN":"……知りませんでした。","ENG":"I... I didn't know.","TWN":"……我不知道這件事。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"그것 때문에 복수하려고 마음 먹으신 건가요?","JPN":"それで復讐しようと決意したんですか？","ENG":"Is that why you swore to get revenge on them?","TWN":"因爲這樣而下決心報仇嗎？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"물론 침식체가 증오스럽긴 하지만, 침식체 몇 마리 잡는다고 그녀가 편히 잠들 거라 생각하진 않아.","JPN":"もちろん侵食体は憎いが、侵食体を倒したからって彼女が浮かばれるとは思ってねえよ。","ENG":"It's not a secret I despise C.O.s, but I don't think killing a few of them will allow her to rest in peace.","TWN":"雖然我很憎恨侵蝕體，但我不認爲殺幾隻侵蝕體就能讓她安息。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"더 이상 나같은 외톨이가 나와선 안 된다는 각오였어. 그래서 나름 내 기술이 군에 보탬이 될 거라 생각하고 지원했지.","JPN":"もう俺のような一人ぼっちを出さないって覚悟したからだ。それで俺の技術がそれなりに軍の役に立つと思って志願したわけさ。","ENG":"I promised myself that I wouldn't let another person lose their loved one like me. That's why I decided to join and use my skills to help out the army.","TWN":"我下定決心，希望不再有人像我一樣成為孤家寡人，然後覺得我的技術可以對軍隊有幫助，於是就報名從軍。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"뭐, 지휘관님이 나타난 뒤론 내 특기도 별볼일 없어졌지만 말이야.","JPN":"まあ、指揮官が現れてからは、俺の特技もつまらなくなっちまったがな。","ENG":"But, my specialty seems to be no use after our commander joined...","TWN":"不過指揮官出現後，我的專長就變得沒什麼看頭。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"그래도 대포는 누구보다 잘 다루시잖아요. 이번에 지휘관님 지시로 폭탄도 엄청나게 만들었고.","JPN":"でも大砲は誰よりもうまく扱えるじゃないですか。この前は指揮官の指示で爆弾もいっぱい作りましたし。","ENG":"But you're still the best with cannons around here! You even made those incredible explosives on the Commander's orders!","TWN":"但你很會操控大砲的嘛！這次在指揮官的指示下，還製作那麼多炸彈。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_LAUGH"}}}}]`);export{e as default};